1403:     if (redirectedReference) {
1404:         compilerOptions = redirectedReference.commandLine.options;
1405:     }
1406:     if (traceEnabled) {
1407:         trace(host, Diagnostics.Resolving_module_0_from_1, moduleName, containingFile);
1408:         if (redirectedReference) {
1409:             trace(host, Diagnostics.Using_compiler_options_of_project_reference_redirect_0, redirectedReference.sourceFile.fileName);
1410:         }
1411:     }
