1416:         if (traceEnabled) {
1417:             trace(host, Diagnostics.Resolution_for_module_0_was_found_in_cache_from_location_1, moduleName, containingDirectory);
1418:         }
1419:     }
1420:     else {
1421:         let moduleResolution = compilerOptions.moduleResolution;
1422:         if (moduleResolution === undefined) {
